var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"비상, 비상!! 집결하라!! 다크─세븐!!","JPN":"非常事態！　非常事態！！　集結せよ！！　ダーークセブン！！","ENG":"Danger! Danger!! Assemble!! DAARK SEVEN!!","TWN":"緊急，緊急！立即集合！Dark 7！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"비상! 비상!! 일어나라!! 사이버─캣!!","JPN":"非常事態！　非常事態！！　起きろ！！　サイバーーキャット！！","ENG":"Danger! Danger!! Wake up, Cyber Caaat!!","TWN":"緊急情況！快起來！賽博——貓！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"으으, 진짜!! <color=#ff3636>[검열됨]</color>!! <color=#ff3636>[검열됨]</color>!!","JPN":"うう、もう！！　<color=#ff3636>[検閲済]</color>！！　<color=#ff3636>[検閲済]</color>！！","ENG":"Ugh, c'mon!! <color=#ff3636>[BLEEP]</color>!! <color=#ff3636>[BLEEP]</color>!!","TWN":"呃呃，討厭！<color=#ff3636>[嗶——]</color>！！<color=#ff3636>[嗶——]</color>！！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"<color=#ff3636>[검열됨]</color>!! <color=#ff3636>[검열됨]</color>!! 니들은 잠도 없어!?","JPN":"<color=#ff3636>[検閲済]</color>！！　<color=#ff3636>[検閲済]</color>！！　アンタたちは寝ないっての！？","ENG":"<color=#ff3636>[BLEEP]</color>!! <color=#ff3636>[BLEEP]</color>!! Don't you guys even SLEEP?!!","TWN":"<color=#ff3636>[嗶——]</color>！！<color=#ff3636>[嗶——]</color>！！你們都不睡覺的嗎？！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"기껏 연차까지 쓰고 수면보충 좀 하려는데, 꼭두새벽부터 시끄럽게 무슨 짓이야, 대체!?","JPN":"人がせっかく有給休暇まで使って睡眠補充しようとしてるのに、朝っぱらからうるさいのよ、もう！！","ENG":"I even used my PTO to get some well-needed sleep, and you HAD to cause a ruckus this early in the morning?!","TWN":"我好不容易休假想補眠，你們大清早的到底在吵什麼？！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"어이, 어이, 진정하라구. 사이버 캣. 벌써 해가 중천이야.","JPN":"ちょっと、ちょっと、落ち着いてよ。サイバーキャット。もうお昼よ。","ENG":"Whoa, whoa. Calm down, Cyber Cat. It's already noon.","TWN":"喂喂，冷靜點，賽博貓，現在都已經中午咧。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"일찍 일어나는 해커가 정보를 낚는 법이라고.","JPN":"早起きするハッカーこそ情報キャッチできるものよ。","ENG":"The early hacker catches the info.","TWN":"俗話說早起的駭客才有情報可釣。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"앨버트 말이 옳아. 다크─세븐의 일원으로서 좀 더 자각을 가지는 게 어때, 사이버 캣?","JPN":"そのとおり。ダーークセブンの一員として、もっと自覚を持った方がいいんじゃないか？　サイバーキャット。","ENG":"Albert's right. Why don't you be a bit more diligent? After all, you're a member of Daark Seven!","TWN":"亞伯特說得對。身為Dark 7的一員，能不能有點自覺，賽博貓？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"……아하, 그러셔?","JPN":"……へえ、そうくるんだ？","ENG":"...Hah. Really?","TWN":"……哀，是嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그래. 어디 얼마나 중대한 일로 호출하셨는지 들어볼까?","JPN":"いいわ。そんなに言うなら、どれだけ重大な仕事で呼び出したのか、聞いてみようじゃないの。","ENG":"OK. So what crucial matter is this about?","TWN":"好吧，那就讓我來聽聽，你們到底有什麼情報？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"반드시 중요한 일이어야만 할 거야.","JPN":"重大なことじゃなかったら、わかってるわよね？","ENG":"It better be something important.","TWN":"最好是有什麼重要的事。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그렇지 않으면 착불로 궤도 미사일을 받아보게 될 테니까.","JPN":"着払いで軌道ミサイルを送りつけてやるから。","ENG":"Or else, you'll be getting a very special package called a ballistic missile.","TWN":"否則我會用貨到付款的方式，讓你們收到軌道導彈！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"후, 후후…… 기대하시라!","JPN":"ふ、ふふ……任せて！","ENG":"Ha, ha ha... Prepare yourself!","TWN":"呵呵……敬請期待吧！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"이 몸께서는 이번에 개최될 관리국 테크 컨퍼런스에 대한 미공개 홍보영상을 빼돌렸단 말씀!","JPN":"この私が、今度開催される管理局のテックカンファレンスについての未公開宣伝映像を盗み取ってきたのよ！","ENG":"Because I got leaks of the unreleased promotional video for the Administration Tech Conference that's happening soon!","TWN":"最近不是要舉辦管理局技術大會嗎？我把他們還沒公開的宣傳影片給弄來囉！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"테크 컨퍼런스? 매년 관리국 기술을 시연하는 박람회를 말하는 거지?","JPN":"テックカンファレンス？　毎年管理局の技術を披露する博覧会のことよね？","ENG":"Tech Conference? The annual expo where they showcase the Administration's technology?","TWN":"技術大會？你說的是每年展示管理局技術的博覽會吧？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"정식 라이센스가 없으면 입장할 수도 없는 행사잖아!?","JPN":"正式ライセンスがないと入場すらできないイベントじゃないか！？","ENG":"You can't even get in without an official license!","TWN":"你說那個沒有通行證根本進不去的博覽會嗎？！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"엣헴! 좀 더 찬양해도 좋다고, 제군들?","JPN":"えっへん！　もっと褒めてくれてもいいのよ、諸君？","ENG":"Ahem! Feel free to continue with the compliments.","TWN":"嘿嘿！快誇我！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"이번 테크 컨퍼런스에서는 관리국의 가상 현실 기술이 시연될 예정이야.","JPN":"今度のテックカンファレンスでは管理局のVR技術が披露される予定なの。","ENG":"This Tech Conference is going to showcase the Administration's virtual reality technology.","TWN":"在這次的技術大會上，管理局會展示VR技術！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"관리국의 소개에 따르면, 장소나 환경에 구애받지 않고 어디든 구현할 수 있다고 해.","JPN":"管理局の説明によると、場所や環境に左右されず、どこにでも具現可能らしいよ。","ENG":"According to the Administration, it can be implemented anywhere, regardless of the location or environment.","TWN":"據管理局的介紹，這個技術不受場地和環境的限制，可以在任何地方使用！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"오, 꽤 하는데? 그래서? 관리국은 그 기술로 뭘 보여줄 예정인데?","JPN":"おお、なかなかやるじゃない。で？　管理局はその技術で何を見せてくれる予定なの？","ENG":"Oh, not bad. So? What is the Administration gonna do with that technology?","TWN":"噢，還不錯嘛？然後呢？管理局準備用那個技術做什麼？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"후, 후후…… 놀라지 마시라!","JPN":"ふ、ふふ……驚くなかれ！","ENG":"Ha, ha ha... Brace yourself...","TWN":"哼哼哼哼……你可不要被嚇到！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"관리국은 그 기술을 활용하여, <color=#ffd34c>유령의 집</color>을 기획하고 있어!","JPN":"管理局はその技術を活用して、<color=#ffd34c>お化け屋敷</color>を企画してるの！","ENG":"The Administration is going to utilize that technology... to organize a <color=#ffd34c>haunted house</color>!","TWN":"管理局準備利用那個技術，打造一個<color=#ffd34c>鬼屋</color>！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그러니까, 관리국이 그 잘나 빠진 기술력으로 고작 유령의 집이나 만든 다는 말이지?","JPN":"つまり、管理局はそのご大層な技術力でお化け屋敷なんかを作るってことね。","ENG":"So, the Administration's gonna use their fancy technology to make a childish haunted house?","TWN":"就是說，管理局就打算用那個了不起的技術做一個鬼屋？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"아하~ 그렇구나~ 그럼 이제 너희 집 주소를 불러줄래, 앨버트?","JPN":"へえ～そうなんだ～じゃ、そろそろアンタたちの住所を教えてくれる？　アルバート？","ENG":"Ohh! Of course! Now, will you tell me your address, Albert?","TWN":"啊哈～這樣啊～那現在可以把你們的住址告訴我了嗎，亞伯特？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"굳이 최신 기술까지 쓰지 않아도, 미사일 한방이면 유령 나오는 집을 만들 수 있다는 걸 보여줄 테니까.","JPN":"最新技術まで使わなくとも、ミサイル一発で幽霊が出る家を作れるってところを見せてあげるから。","ENG":"I'll showcase my own haunted house with just one missile. I don't need any state-of-the-art technology.","TWN":"我可以讓你們見識一下，不使用最新技術，怎樣只靠一發導彈打造鬼屋。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"후후후, 역시 쉽게 믿지 못하는군 사이버 캣.","JPN":"ふふふ、やっぱりそう簡単に信じられないよね、サイバーキャット。","ENG":"Ha ha ha, I see you don't believe me, Cyber Cat.","TWN":"哼哼哼，你果然不會輕易相信，賽博貓。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"하긴, 나도 처음에는 내 눈을 의심했으니까.","JPN":"まあ、私も最初は自分の目を疑ったから。","ENG":"I can't blame you. I, too, couldn't believe what I was seeing.","TWN":"剛開始的時候，我也以為是我自己看錯了。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"하지만 이 영상을 보고도 그런 말을 할 수 있을까?","JPN":"でも、この映像を見てもそんなことを言えるかな？","ENG":"But will you feel the same way even after watching this video?","TWN":"但是你看了這個影片之後就不會那麼說了。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_QM","text":{"KOREA":"……오, 오싹오싹 고스트 하우스에 오신 걸 환영합니다, 카운터 여러분.","JPN":"……ぞ、ゾクゾク・ゴーストハウスへようこそ、カウンターの皆さん。","ENG":"...W-welcome to the Creepy Ghost House, Counters.","TWN":"……各，各位制裁者，歡迎來到毛骨悚然鬼屋。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……대원들의 훈련 경과는 순조롭습니다, 대령님.","JPN":"……隊員たちの訓練経過は順調です、大佐。","ENG":"...The troops' training is going smoothly, Colonel.","TWN":"……隊員們的訓練過程非常順利，上校。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실제로 새 훈련법을 도입한 후에 작전 효율성이 약 32% 정도 향상되었죠.","JPN":"実際に新しい訓練方法を導入した後、作戦の効率性が約32％程向上しました。","ENG":"Operation efficiency has increased by roughly 32% since implementing the new training plan.","TWN":"實際上，引進新的訓練方法之後，作戰效率提高了32%左右。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이대로만 한다면, 다음 분기에 있을 정식 평가도 문제 없을…….","JPN":"このまま行けば、次の四半期の正式評価も問題ないはず……","ENG":"At this rate, there should be no issues in the official evaluation for the next quarte–","TWN":"照這樣下去，下個季度的評鑑也不會有什麼問……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하아……! 하아……! 나 좀 봐, 버터맨!! 속보야, 속보라고!!","JPN":"はあ……！　はあ……！　ちょっと、バターマン！！　速報よ、速報！！","ENG":"*Huff...!* *Huff...!* I need to talk to you, Sleazeball!! I got news, BIG NEWS!!","TWN":"哈啊……！哈啊……！小白臉，小白臉！出大事啦！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"응, 무슨 일이야, 실비아? 오늘 휴가였던 걸로 알고 있는데?","JPN":"うん？　どうしたんだ、シルビア。今日は休みじゃなかったのか？","ENG":"Okay. What's going on, Sylvia? I thought you were on vacation today.","TWN":"嗯，怎麼了，希爾維亞？你今天不是休假嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금 휴가가 중요한 게 아니라니까! 대박 사건을 건졌다고, 대박 사건!","JPN":"今休んでる場合じゃないのよ！　大事件なの、大事件！","ENG":"Vacation is not the issue here! I have a scoop! A BIG SCOOP!","TWN":"現在重要的不是休假！有大新聞，大新聞！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"글쎄, 카일이 말이지…….","JPN":"それがね、カイルが……","ENG":"So you know Kyle, he–","TWN":"我跟你講，凱爾他……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨. 지금은 업무 보고 중인 거 안 보입니까?","JPN":"シルビアさん。今は業務報告中ですが。","ENG":"Sylvia. Can't you see that I am in the middle of reporting something?","TWN":"希爾維亞，你沒看見我正在彙報工作嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭔지는 몰라도 영양가 없는 잡담은 나중에 하십쇼.","JPN":"何だか知りませんが、無意味な雑談は後にしてください。","ENG":"Whatever your trivial gossip may be, you can wait until the reports are finished.","TWN":"雖然我不知道你有什麼事，但沒有意義的閒話還是等會兒再說吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……우왓!? 카, 카일!? 카일이랑 통신 중이었어?","JPN":"……うわっ！？　か、カイル！？　カイルと通信中だったの？","ENG":"Wha–?! K-Kyle!? You were talking to Kyle?!","TWN":"……哇咧？！凱，凱爾？！你正在和凱爾通話？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭡니까, 왜 그렇게 당황하죠? 저한테 뭐 숨기는 거라도 있습니까?","JPN":"何ですか、どうしてそんなに慌ててるんですか？　僕に何か隠し事でも？","ENG":"What is it? Why are you flustered? Are you hiding something from me?","TWN":"怎麼回事，幹嘛那麼驚慌？難道你有什麼事瞞著我？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……아, 아, 아무것도 아냐!","JPN":"……な、な、何でもないわ！","ENG":"...N-n-nothing!","TWN":"……沒，沒，沒什麼！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그, 그럼 아무것도 아니지! 하, 하하하.","JPN":"そ、そうよ、何でもないの！　ハ、ハハハ。","ENG":"N-nothing at all! Ha... Ha ha ha.","TWN":"當，當然沒什麼囉！哈，哈哈哈。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"수상하군요. 저 몰래 무슨 짓을 벌인 겁니까?","JPN":"怪しいですね。僕に内緒で、何をしでかしたのですか？","ENG":"You are acting quite suspiciously. What did you do?","TWN":"真是可疑，你是不是偷偷背著我做了什麼？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 실비아가 이렇게 당황하는 모습은 오랜만인데?","JPN":"はは、シルビアがこんなに慌てる姿は久々だな。","ENG":"Ha ha, it's been a while since I've seen Sylvia so flustered.","TWN":"哈哈，好久沒見希爾維亞這麼驚慌了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 아무튼! 카일이랑 얘기 끝나면 나 좀 봐, 버터맨!!","JPN":"と、とにかく！　カイルとの話が終わったら、ちょっとアタシのところに来て、バターマン！","ENG":"A-anyway! We gotta talk after you're done with Kyle, Sleazeball!!","TWN":"總，總之！等凱爾彙報完之後我們談談吧，小白臉！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"진짜, 진짜 중요한 이야기가 있으니까!","JPN":"本当に、本っ当に大事な話があるから！","ENG":"It's super, super important!","TWN":"因為真的是非常非常重要的事情！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그러니까, 결론은 너랑 유령의 집을 같이 가달라는 말이야?","JPN":"それで、結論としては、俺に一緒にお化け屋敷に行ってほしいってことか？","ENG":"So, in conclusion, you want me to go to a haunted house with you?","TWN":"所以結論就是，你想讓我陪你一起去鬼屋？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 설마 이런 식으로 데이트 신청을 받을 줄은 몰랐는걸?","JPN":"はは、まさかこんな風にデートに誘われるなんてな。","ENG":"Ha ha, I never thought anyone would ask me out to a haunted house.","TWN":"哈哈，沒想到你會以這種方式約我出去？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그런데 어쩌나, 사내연애는 별로 내 취향이 아닌데.","JPN":"でも悪いな、職場恋愛は俺の好みじゃないんだ。","ENG":"Unfortunately, dating coworkers is not really my thing.","TWN":"但怎麼辦呢，我對辦公室戀情沒興趣欸。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하아, 개소리 하는 걸 보니 전혀 못 알아먹었네.","JPN":"はあ、ばかなこと言ってるところを見ると、全っ然理解してないわね。","ENG":"*Sigh* You're still not getting the point.","TWN":"哼，看你鬼話連篇的樣子，是一點都沒聽懂我說的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하긴, 믿어주리라고는 기대도 안 했어. 나도 보기 전까진 못 믿었으니까.","JPN":"まあ、信じてくれるなんて期待してなかったけどね。アタシだって実際見るまでは信じられなかったから。","ENG":"Well, I didn't expect you to believe me right away. I didn't believe it until I saw it myself.","TWN":"不過我也沒指望你會信，因為在看到影片之前我也是不相信的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"대체 뭔데 그렇게 호들갑이야? 설마 유령이 무서워서 그러는 건 아닐 테고.","JPN":"大げさに、いったい何なんだ？　まさか、幽霊が怖いってわけでもないだろうし。","ENG":"What's all the fuss about? You're not afraid of ghosts, are you?","TWN":"到底是什麼東西讓你這麼大驚小怪的？你不會是怕鬼吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 어떤 의미에서 유령보다 더 무섭고 끔찍할지도 몰라.","JPN":"いや、ある意味、幽霊より怖くてぞっとするかもしれないわよ。","ENG":"Nope, but in some ways, this might be more terrifying than ghosts.","TWN":"不，從某種意義上來說，那也許比鬼更可怕。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"영상을 틀기 전에 하나만 물을게, 버터맨.","JPN":"バターマン、映像を再生する前に一つだけ聞くけど。","ENG":"Before I play the video, I have one question, Sleazeball.","TWN":"在放影片之前，我要問你一個問題，小白臉。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"카일의 인적 사항에 누나나 여동생은 없었지?","JPN":"カイルにお姉さんとか妹はいなかったわよね？","ENG":"Do you know if Kyle has a sister or something?","TWN":"凱爾的個人資料裡並沒有寫他有姊姊或妹妹吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"응? 그게 무슨……?","JPN":"うん？　それはどういう……？","ENG":"Huh? What do you mean...?","TWN":"嗯？什麼意思……？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_QM","text":{"KOREA":"……오, 오싹오싹 고스트 하우스에 오신 걸 환영합니다. 카운터 여러분.","JPN":"……ぞ、ゾクゾク・ゴーストハウスへようこそ、カウンターの皆さん。","ENG":"...W-welcome to the Creepy Ghost House, Counters.","TWN":"……各，各位制裁者，歡迎來到毛骨悚然鬼屋。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_QM","text":{"KOREA":"오늘은 저 빨간 망토와 함께 이 고스트 하우스를 탐방하는 시간을 가질 거예요.","JPN":"今日は私、赤ずきんと一緒にこのゴーストハウスを探ってみましょう。","ENG":"Today you're going to explore this haunted house with me, Red Riding Hood.","TWN":"今天就和小紅帽一起探訪一下這個鬼屋吧。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_QM","text":{"KOREA":"우선, 입장하기 전에 크게 심호흡을 들이 마시고…….","JPN":"まず、入場する前に大きく深呼吸をして……","ENG":"First, take a deep breath before entering, and...","TWN":"進鬼屋之前，需要先做個深呼吸……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_QM","text":{"KOREA":"히, 히힉!?","JPN":"ひ、ひいっ！？","ENG":"E-eeek!","TWN":"嗚，嗚嗚？！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APHALLOWEEN_QM","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_QM","text":{"KOREA":"바, 바, 바, 방 방금 뭔가가…… 절 건드리지 않았나요!?","JPN":"い、い、い、い、今何かが……私に触れませんでしたか！？","ENG":"D-d-d-did something just... touch me?!","TWN":"剛，剛，剛，剛剛是什麼東西……碰我？！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_QM","text":{"KOREA":"누구에요!! 장난치지 말고, 당장 나오세요! 당장!","JPN":"誰ですか！！　ふざけていないで今すぐ出てきなさい！　早く！","ENG":"Who is it?! Stop joking around! Come out, now!","TWN":"是誰！不要開玩笑，馬上給我出來！立刻！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……처음에는 당연히 합성된 가짜 동영상이라고 생각했는데, 감별 프로그램을 돌려보니 그건 아니었어.","JPN":"……最初は当然捏造された映像だと思ったんだけど、鑑別プログラムにかけてみたらそうじゃなかった。","ENG":"...At first, I thought it was fake, that it was deepfaked or something. But I ran a forensics program and it didn't catch anything.","TWN":"……一開始我還以為這是合成的假影片，但經過鑒定之後才發現是真的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 가능성은 두 가지 중 하나.","JPN":"だとすると、可能性は二つ。","ENG":"Which means there are only two options left.","TWN":"那就說明，有二個可能性。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"카일을 닮은 여자이거나……","JPN":"カイルに似てる女か……","ENG":"It's a woman who looks like Kyle...","TWN":"一是有個長得很像凱爾的女人……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"진짜 여장한 카일이거나!","JPN":"本当に女装したカイルか！","ENG":"Or it's Kyle dressed up as a woman!","TWN":"二是凱爾男扮女裝！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"에이, 실비아. 아무리 그래도 카일을 대체 뭐라고 생각하는 거야?","JPN":"おい、シルビア。カイルのこと何だと思ってるんだ？","ENG":"C'mon, Sylvia. Who do you think Kyle is?","TWN":"哎呀，希爾維亞，再怎麼說，你也不能把凱爾想得那麼不堪吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"상식적으로 그냥 닮은 사람이겠지. 세상에는 자길 닮은 사람이 세 명은 있다고 하잖아?","JPN":"常識的に考えて単なる他人の空似だろ。世の中には自分に似たやつが三人はいるっていうじゃないか。","ENG":"It's probably just someone who looks like him. They say you have at least three doppelgangers out there in the world.","TWN":"按常理來說，就是長得像而已。不是說在這個世界上，起碼會有三個跟自己長得很像的人嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그러고보니…… 예전에 카일을 닮은 여자가 연구 기지를 습격했다는 보고가 있었던 것 같기도 하고…….","JPN":"そういえば……前にカイルに似た女が研究基地を襲撃したという報告があったような……","ENG":"But then again... I vaguely remember a report about a woman who looks like Kyle ambushing our research facilities…","TWN":"這麼說來……我好像看過一則報導，說是有一個酷似凱爾的女人襲擊研究基地……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"사람 일 모르는 거야, 버터맨.","JPN":"人なんてわかんないものよ、バターマン。","ENG":"You never know, Sleazeball.","TWN":"人心難測，小白臉。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"인터넷만 봐도, 말도 안 되는 취향을 가진 사람들이 얼마나 많은데.","JPN":"ネットでも、あり得ないフェチを持ってる人がごまんといるんだから。","ENG":"Just look at the internet. There are countless people with absurd tastes.","TWN":"光是在網路上，就能看到很多興趣古怪的人。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"혹시, 그 애늙은이가 우리 앞에서는 샌님인 척하고…… 뒤에서는 음습한 취미를 가지고 있다고 해도 그리 이상한 일이 아니야.","JPN":"あのませガキだって、アタシたちの前ではいい子のふりながら……裏で陰険な趣味を持っていたとしても、そうおかしくはないわ。","ENG":"That old soul acts all uptight in front of us... but it's possible that he dabbles in shady hobbies behind our backs.","TWN":"那個小老頭就算在我們面前裝成一副嚴肅的樣子……但背地裡卻有著不可告人的嗜好也不是什麼稀奇的事。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그건, 그냥 네가 인터넷을 너무 많이 한 거 같은데……?","JPN":"そりゃ、お前がただのネットの見すぎなんじゃ……？","ENG":"That sounds to me like you spend too much time on the internet.","TWN":"你是不是上網上多啦……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아무튼 난 내 눈으로 직접 확인하고야 말겠어.","JPN":"とにかく、直接この目で確かめてやる。","ENG":"Whatever the case, I gotta see it for myself.","TWN":"總之，我必須要親眼確認一下。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"흥! 두고 보자고, 카일!","JPN":"フン！　見てなさいよ、カイル！","ENG":"Hmph! Just you wait, Kyle!","TWN":"哼！走著瞧吧，凱爾！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"반드시 네 약점을 들춰내서, 리프노드의 통제권을 완전히 되찾고 말 테니까!!","JPN":"絶対アンタの弱点を暴いて、リーフノードの操作権限を完全に取り戻してやるんだから！！","ENG":"I'm gonna find out your weakness and get back total control of Leaf Node!","TWN":"我一定會找出你的弱點，然後完全奪回節點的控制權！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하. 역시 실비아야. 다른 꿍꿍이가 있었구만…….","JPN":"はは。さすがはシルビアだ。他に目的があったんだな……","ENG":"Ha ha. Of course you had ulterior motives, Sylvia.","TWN":"哈哈，不愧是希爾維亞，果然打著其他算盤……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"엇!? 방금, 저 사람……. 빨간 망토 맞지?","JPN":"あっ！？　今の、あの人……赤ずきんだよね？","ENG":"Huh!? Just now. Was that... Red Riding Hood?","TWN":"欸？！剛剛那個人……是穿著紅色披風吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"빨리 따라가자, 버터맨!","JPN":"早く追いかけるのよ、バターマン！","ENG":"Let's follow her, Sleazeball!","TWN":"快追上去，小白臉！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어디갔지, 분명 여기로 들어왔는데……?","JPN":"どこに行ったのかしら？　確かにこっちに入ったんだけど……？","ENG":"Where is she? I know she went this way...","TWN":"去哪了，我明明看到她進來這裡了……？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"호오, 이 풍경이 다 만들어진 거란 말이지?","JPN":"ほう、この風景が全部バーチャルってことだろ？","ENG":"Huh, so this view is all made up?","TWN":"哇喔，這些場景都是假的吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"꽤 그럴 싸한데, 이 기술을 훈련에 도입하면 상당히 도움이 되겠어.","JPN":"かなり現実に近いな。この技術を訓練に導入すれば大いに役立ちそうだ。","ENG":"Not bad. It would be of great help if we implemented this technology into our training.","TWN":"像不像三分樣，把這個技術應用到訓練中的話應該很有幫助。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"으휴, 이 근육뇌야. 훈련 생각 같은 건 나중에 하고 지금은 빨리 빨간 망토의 정체를…….","JPN":"まったく、この脳筋バカときたら。訓練のことなんか後回しにして、今は早く赤ずきんの正体を……","ENG":"Ugh, is your brain made up of muscles too? Forget about training, just focus on uncovering who that Red Riding–","TWN":"嘖，你這個肌肉腦，訓練什麼的等以後再說，現在最重要的是要弄清楚紅色披風的……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_QM","text":{"KOREA":"저, 혹시 델타 세븐의 제이크 대령님 맞으신가요?","JPN":"あの、もしかしてデルタセブンのジェイク大佐ではありませんか？","ENG":"Um, are you Colonel Jake Walker of Delta Seven?","TWN":"請問，你是第七三角洲部隊的傑克上校嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아, 네. 그렇습니다만. 그쪽의 레이디는 성함이…….","JPN":"あ、はい。そうですが。そちらのレディーは……？","ENG":"Oh, yes. I am. And you are, my lady...?","TWN":"是的，沒錯。請問小姐貴姓……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"아, 반갑습니다. 전 오피셜 서포트의 캐시라고 해요. 테크 컨퍼런스의 취재를 맡고 있죠.","JPN":"あ、はじめまして。私はオフィシャルサポートのキャシーと言います。テックカンファレンスの取材を担当しております。","ENG":"Ah, nice to meet you. I'm Cathy, from Official Support. I'm covering the tech conference.","TWN":"很高興見到你，我是支援小隊的凱西，來技術大會進行採訪工作。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"리플레이서 사태를 해결한 델타 세븐의 영웅을 이렇게 직접 보게 되서 무척 영광이네요.","JPN":"リプレイサー事件を解決したデルタセブンの英雄にこうして直接お会いできるなんて、大変光栄です。","ENG":"It's an honor to meet the hero of Delta Seven who resolved the Replacer incident.","TWN":"沒想到我能親眼見到解決克隆集團事件的第七三角洲部隊英雄，真是倍感榮幸。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"잠시 이야기 나누고 싶은데 혹시 시간 좀 있으신가요?","JPN":"少々お話を伺いたいんですが、お時間よろしいでしょうか？","ENG":"I'd love to have a word with you. Do you have a moment?","TWN":"我想和你聊一聊，不知道有沒有空呢？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"훗, 별 말씀을. 군인이 당연히 해야 할 일을 했을 뿐입니다.","JPN":"ふっ、なんてことはありません。軍人として当然やるべきことをしたまでです。","ENG":"Heh, no worries. I was just doing what any soldier would do.","TWN":"哈哈，過獎了，我只是做我該做的而已。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"……저, 저, 저, 정말로 그 제이크 워커 대령님이세요?","JPN":"……ほ、ほ、ほ、本当にあのジェイク・ウォーカー大佐ですか？","ENG":"...Um, a-a-are you THE Colonel Jake Walker?","TWN":"……你，你，你，你真的是傑克·沃克上校？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"호, 혹시 싸인 좀 부탁드려도 될까요? 제, 제가 팬이라서요!","JPN":"も、もしかして、サインお願いしてもいいですか？　わ、私、ファンなんです！","ENG":"C-can I get your autograph? I-I'm a huge fan!","TWN":"能，能幫我簽名嗎？我，我是你的粉絲！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 물론이죠. 시간은 얼마든지 있답니다, 아가씨.","JPN":"はは、もちろんです。時間ならいくらでもあります、お嬢さん。","ENG":"Ha ha, of course. I have plenty of time, ladies.","TWN":"哈哈哈，當然可以，我隨時有空，美麗的小姐。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"으으, 이 재수없어, 어제 먹은 점심이 올라올 것 같네.","JPN":"うぐっ、気持ち悪い。昨日食べた昼ごはん、戻しちゃいそう。","ENG":"Ugh, gross. Yesterday's lunch is crawling back up my stomach.","TWN":"矮額！真噁心，我昨天吃的午飯都要吐出來了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그보다, 그 빨간 망토는 어디로 사라졌지?","JPN":"それより、あの赤ずきんはどこに消えたのかしら？","ENG":"Anyway, where's Red Riding Hood?","TWN":"不過那個紅色披風到底去哪啦？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아의 리프노드의 위치를 조회하면…… 여기군.","JPN":"シルビアさんのリーフノードの位置を検索すると……ここか。","ENG":"Tracking Sylvia and Leaf Node's location... leads to here.","TWN":"追蹤希爾維亞節點的位置……在這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그런데, 오싹오싹 고스트 하우스? 대령님과 실비아가 같이 담력 시험을……?","JPN":"ゾクゾク・ゴーストハウス？　大佐とシルビアさんが一緒に肝試しを……？","ENG":"But, Creepy Ghost House? Is Colonel and Sylvia testing their courage here...?","TWN":"毛骨悚然鬼屋？上校和希爾維亞一起……參加試膽大會？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"무언가 이상해. 두 사람은 대체 나에게 뭘 숨기고 있는 거지?","JPN":"怪しい。二人はいったい僕に何を隠しているんだ？","ENG":"Something seems off. What are those two hiding from me?","TWN":"有點奇怪。他們二個到底瞞著我什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"이 축축한 안개…… 바스락 거리는 나뭇잎 소리…… 그리고 이 음산한 분위기……","JPN":"このジメジメした霧……乾いた音を立てる落ち葉……そして、この陰湿な雰囲気……","ENG":"The humid fog... the crisp sound of leaves... and this chilling atmosphere...","TWN":"濕氣的霧……窸窸窣窣的樹葉聲……還有陰森的氛圍……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"몇 번을 봐도 믿을 수 없어……. 이게 다 시뮬레이션일 뿐이라고?","JPN":"何度見ても信じられない……これが全部シミュレーション？","ENG":"No matter how many times I see it, I still can't believe this is all just a simulation...","TWN":"不管看多少次都難以置信……這些真的都只是模擬？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"틀렸어. 내 능력으로도 이곳의 원리를 완벽히는 파악할 수 없어.","JPN":"ダメだわ。私の能力でもここの原理を完璧には把握できない。","ENG":"This is hopeless. I can't fully comprehend how this place works, even with my abilities.","TWN":"糟糕，以我的能力無法完全掌握這裡的原理。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_TECH"},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"대체 관리국이라는 곳은 어떤 기술력을…….","JPN":"いったい管理局というのは、どれだけの技術力を……","ENG":"What kind of technology does the Administration possess–","TWN":"管理局到底是用什麼技術……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……어?","JPN":"……ん？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"……아?","JPN":"……え？","ENG":"...Oh?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_BOTH","text":{"KOREA":"다…… 다, 당신은 또다른 나!?","JPN":"あ……あ、あなたは、もう一人の自分！？","ENG":"You... Y-you, you're me!","TWN":"你……你，你是另一個我？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"역시……!! 그때, 그건 꿈 같은 게 아니었어!!","JPN":"やはり……！！　あの時、あれは夢なんかではなかったんだ！！","ENG":"I knew it...! That wasn't a dream!","TWN":"果然……！那時候並不是做夢！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭡니까, 당신!? 또 이쪽 세계에 무슨 민폐를 끼치러 온 겁니까?","JPN":"何ですか、あなた！！　またこちらの世界に迷惑をかけに来たのですか？","ENG":"What are you doing here?! What trouble are you causing this world now?!","TWN":"你想做什麼？！你來這個世界又想搞什麼鬼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"설마, 이번에도 침식체를 유기하러 온 겁니까?","JPN":"まさか、今回も侵食体を捨てに？","ENG":"Are you here to dispose of more C.O.s?","TWN":"難道是想把更多侵蝕體丟過來嗎！？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"뭔가요, 당신!? 왜 군인이 근무 시간에 여기 있는 거죠?","JPN":"何ですか、あなた！！　なぜ軍人が勤務時間にここにいるのですか？","ENG":"What are YOU doing here?! What is a soldier doing here during work hours?","TWN":"你怎麼回事？！你一個軍人，上班時間為什麼會在這裡？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"명예로운 델타 세븐 요원이 근무 시간에 땡땡이를 치다니, 당신네 델타 세븐은 기강이 참 해이하군요.","JPN":"名誉あるデルタセブンの一員が勤務時間にサボるなんて、そちらのデルタセブンは規律が乱れきっていますね。","ENG":"An honorable member of the Delta Seven, playing hooky during work hours. You Delta Sevens lack discipline, it seems.","TWN":"榮耀的第七三角洲部隊成員居然在上班時間偷懶，這個世界的第七三角洲部隊真是紀律渙散！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하! 군인에 어울리지 않는 건 그쪽도 만만치 않을 텐데요?","JPN":"は！　軍人に相応しくないという点では、そちらも負けていないと思いますが。","ENG":"Hah! Look who's talking about soldiers and discipline.","TWN":"蛤！你也好不到哪去吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그 파렴치한 복장으로 군의 기강을 논하는 게 설득력이 있다고 생각하십니까?","JPN":"その破廉恥な服装で軍の規律を論ずるとは、説得力があると思っているのですか？","ENG":"Do you really think your words carry any weight while wearing that vulgar costume?","TWN":"穿著那一身羞恥的衣服討論部隊紀律，你覺得有說服力嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"흥! 아무것도 모르면서 비웃지 마시죠!","JPN":"フン！　何も知らないくせに、笑わないでください！","ENG":"Hmph! Don't mock me when you don't know the context.","TWN":"哼！你什麼都不不知道，少在那邊指指點點！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"뭐, 뭔가 조금 잘 못되긴 했지만……. 이게 다 우리 세계를 위해서 이렇게 된 거라고요!","JPN":"し、少々手違いがありはしましたけど……これも全部、私たちの世界のためなんです！","ENG":"Th-things took a weird turn, but... all of this is for our world!","TWN":"雖， 雖說是有哪裡不太對勁……但這全都是為了我們的世界！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그런 복장으로…… 세계를 위한다고요!?","JPN":"そんな服装で……世界のため！？","ENG":"For your world... in that outfit?!","TWN":"你說你穿成這樣……是為了世界？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……어, 어떻게?","JPN":"……ど、どうやって？","ENG":"...H-how?","TWN":"……什，什麼意思？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"뭐, 뭐예요?","JPN":"な、何ですか？","ENG":"W-what?","TWN":"你，你幹嘛！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"왜 갑자기 그렇게 뚫어져라 쳐다보시는 거죠!? 기분 나쁘게!!","JPN":"どうして急にじっと見るのですか！？　気持ち悪いです！！","ENG":"Why are you staring so intensely all of a sudden!? It's creepy!","TWN":"為什麼突然那樣盯著我看？！感覺很奇怪！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아니! 그쪽이 그런 파렴치한 복장을 입고 있으니까 볼 수밖에 없는 거 아닙니까!","JPN":"いや！　そちらがそういった破廉恥な服を着ているので、見るしかないではないですか！","ENG":"I mean! It's your fault for wearing something so vulgar!","TWN":"拜託！你穿成這樣，我有可能不看嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"경고했습니다! 이쪽 보지 마세요!","JPN":"警告しました！　こちらを見ないでください！","ENG":"I'm warning you! Stop looking at me!","TWN":"我警告你喔！不准看我！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"저도 좋아서 이런 옷을 입은 게 아니라고요!!","JPN":"私も好きでこんな服を着ているわけではありません！！","ENG":"It's not like I'm wearing this because I like it!!","TWN":"我才不是因為喜歡才穿這身衣服的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};